from contextlib import contextmanager

@contextmanager
def file_reader(filename):
    f = open(filename, 'r')
    try:
        yield f
    finally:
        f.close()

# Class version:
class FileManager:
    def __init__(self, filename):
        self.filename = filename

    def __enter__(self):
        self.file = open(self.filename, 'r')
        return self.file

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.file.close()

